"""
/controls router – send remote and power controls to saved Apple TV devices.
"""

from __future__ import annotations

from typing import Annotated

from fastapi import APIRouter, Depends, HTTPException, status
from pydantic import BaseModel
from sqlmodel import Session, select

from home_automation_server.db.session import get_session
from home_automation_server.models.models import AppleTVDevice, AppleTVPairing
from home_automation_server.services import pyatv_service

router = APIRouter()

SessionDep = Annotated[Session, Depends(get_session)]


class RemoteCommandRequest(BaseModel):
    device_id: int
    command: str


class PowerRequest(BaseModel):
    device_id: int
    turn_on: bool


def _get_device_and_credentials(device_id: int, session: SessionDep) -> tuple[AppleTVDevice, dict[str, str]]:
    device = session.get(AppleTVDevice, device_id)
    if not device:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Device not found")

    pairings = session.exec(
        select(AppleTVPairing).where(AppleTVPairing.device_id == device_id)
    ).all()
    credentials = {p.protocol: p.credentials for p in pairings}

    if not credentials:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="No saved credentials for this device. Pair first.",
        )

    return device, credentials


@router.get("/commands", summary="List supported remote commands")
def list_commands():
    return sorted(pyatv_service.REMOTE_COMMAND_MAP.keys())


@router.post("/command", summary="Send a remote command")
async def send_command(body: RemoteCommandRequest, session: SessionDep):
    device, credentials = _get_device_and_credentials(body.device_id, session)

    try:
        await pyatv_service.send_remote_command(
            device.identifier,
            device.ip_address,
            credentials,
            body.command,
        )
    except ValueError as exc:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail=str(exc))
    except RuntimeError as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail=str(exc))

    return {"status": "ok", "device": device.name, "command": body.command}


@router.post("/power", summary="Turn a device on or off")
async def send_power(body: PowerRequest, session: SessionDep):
    device, credentials = _get_device_and_credentials(body.device_id, session)

    try:
        await pyatv_service.power_toggle(
            device.identifier,
            device.ip_address,
            credentials,
            body.turn_on,
        )
    except RuntimeError as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail=str(exc))

    return {
        "status": "ok",
        "device": device.name,
        "power": "on" if body.turn_on else "off",
    }

"""
/ui router – Jinja2 template-rendered pages.
"""

from __future__ import annotations

from typing import Annotated

from fastapi import APIRouter, Depends, Request
from fastapi.responses import HTMLResponse
from fastapi.templating import Jinja2Templates
from sqlmodel import Session, select

from home_automation_server.db.session import get_session
from home_automation_server.models.models import (
    AppleTVDevice,
    AppleTVPairing,
    AutomationFlow,
    AppLaunchConfig,
)

router = APIRouter()
templates = Jinja2Templates(directory="home_automation_server/frontend/templates")

SessionDep = Annotated[Session, Depends(get_session)]


@router.get("/", response_class=HTMLResponse, include_in_schema=False)
def ui_index(request: Request, session: SessionDep):
    devices = session.exec(select(AppleTVDevice)).all()
    return templates.TemplateResponse(
        "index.html", {"request": request, "devices": devices}
    )


@router.get("/devices", response_class=HTMLResponse, include_in_schema=False)
def ui_devices(request: Request, session: SessionDep):
    devices = session.exec(select(AppleTVDevice)).all()
    return templates.TemplateResponse(
        "devices.html", {"request": request, "devices": devices}
    )


@router.get("/pairing", response_class=HTMLResponse, include_in_schema=False)
def ui_pairing(request: Request, session: SessionDep):
    devices = session.exec(select(AppleTVDevice)).all()
    pairings = session.exec(select(AppleTVPairing)).all()
    # Build a mapping device_id → list of pairings
    pairing_map: dict[int, list] = {}
    for p in pairings:
        pairing_map.setdefault(p.device_id, []).append(p)
    return templates.TemplateResponse(
        "pairing.html",
        {"request": request, "devices": devices, "pairing_map": pairing_map},
    )


@router.get("/automations", response_class=HTMLResponse, include_in_schema=False)
def ui_automations(request: Request, session: SessionDep):
    flows = session.exec(select(AutomationFlow)).all()
    devices = session.exec(select(AppleTVDevice)).all()
    device_map = {d.id: d for d in devices}
    return templates.TemplateResponse(
        "automations.html",
        {"request": request, "flows": flows, "devices": devices, "device_map": device_map},
    )


@router.get("/apps", response_class=HTMLResponse, include_in_schema=False)
def ui_apps(request: Request, session: SessionDep):
    configs = session.exec(select(AppLaunchConfig)).all()
    devices = session.exec(select(AppleTVDevice)).all()
    device_map = {d.id: d for d in devices}
    return templates.TemplateResponse(
        "apps.html",
        {"request": request, "configs": configs, "devices": devices, "device_map": device_map},
    )

